                subnetMask,
                vnetSubnetResourceId,
                vnetTrafficTag,
                subnetTrafficTag,
                action,
                tag,
                priority,
                name,
                description,
                headers ?? new ChangeTrackingDictionary<string, IList<string>>(),
                default);
        }

